INSERT INTO `berita` (`id`, `type`, `judul`, `slug`, `teras_berita`, `tubuh_berita`, `gambar`, `sumber_gambar`, `penulis`, `tags`, `created_at`, `updated_at`, `status`, `views`) VALUES
(8, 'berita', 'Lazismu AG Raya Gelar Pertemuan di Tulungagung, Bahas Solusi Bersama di Jalur Lintas Selatan', 'lazismu-ag-raya-gelar-pertemuan-di-tulungagung-bahas-solusi-bersama-di-jalur-lintas-selatan', 'TULUNGAGUNG – Lembaga Amil Zakat Infaq dan Shadaqah Muhammadiyah (Lazismu) wilayah AG Raya mengadakan pertemuan penting di Tulungagung, tepatnya di kawasan Jalur Lintas Selatan (JLS) Tulungagung, Sabtu (21/08/2025).', 'Acara ini dikemas dalam bentuk Coaching Clinic yang menghadirkan jajaran pimpinan Lazismu Jawa Timur. Suasana pertemuan berlangsung hangat, penuh antusiasme, dan diwarnai diskusi intens terkait problematika yang dihadapi Lazismu daerah.\r\n\r\nPertemuan dipandu oleh moderator Hendra Pornama. Ia membuka kegiatan dengan semangat kebersamaan bahwa Lazismu daerah harus terus bersinergi, saling menguatkan, dan mencari solusi bersama atas dinamika pengelolaan zakat, infaq, dan sedekah di lapangan.\r\n\r\nHadirkan Tiga Pemateri Lazismu Jatim\r\n\r\nDalam kesempatan ini, Lazismu Jawa Timur menghadirkan tiga narasumber utama.\r\n\r\nPertama, Aditio Yudhono, Manager Program Lazismu Jatim, yang memaparkan pentingnya inovasi program dan keberlanjutan manfaat bagi penerima zakat. “Lazismu tidak hanya menyalurkan bantuan, tapi juga menciptakan perubahan yang berkelanjutan. Itu membutuhkan desain program yang kuat, berbasis data, dan menyentuh kebutuhan riil masyarakat,” jelasnya.\r\n\r\nKedua, Agus Lukman, Manager Area Lazismu Jatim, yang menekankan pentingnya tata kelola dan sinergi antar-daerah. Menurutnya, Lazismu harus hadir tidak sekadar sebagai pengumpul dana, tetapi juga sebagai penggerak kolaborasi dakwah dan pemberdayaan.\r\n\r\n“Lazismu di tiap daerah punya potensi besar. Namun kalau jalan sendiri-sendiri hasilnya tidak maksimal. Sinergi ini yang kita perkuat agar ke depan Lazismu bisa lebih kokoh dan memberi dampak lebih luas,” ujarnya.\r\n\r\nKetiga, Rosi Hervita, Manager Fundraising Lazismu Jatim, yang membagikan kiat-kiat penggalangan dana kreatif. Ia menekankan perlunya pendekatan yang segar dan sesuai dengan tren masyarakat saat ini. “Donatur harus dilibatkan, diajak merasakan dampak nyata dari kontribusi mereka. Dengan begitu, loyalitas mereka akan tumbuh dan keberlanjutan pendanaan program terjaga,” paparnya.\r\n\r\nAntusiasme Lazismu Daerah\r\n\r\nPara peserta dari berbagai daerah yang tergabung dalam Lazismu AG Raya tampak antusias. Mereka saling melempar pertanyaan, mengutarakan pengalaman lapangan, hingga mengkritisi hal-hal teknis yang selama ini menjadi kendala.\r\n\r\nDiskusi berlangsung hidup. Beberapa pertanyaan muncul seputar penguatan SDM, transparansi laporan, strategi digital fundraising, hingga cara menjaga kepercayaan publik di tengah tantangan zaman.\r\n\r\nSalah satu peserta mengungkapkan, “Kami sering menemui kendala di lapangan terkait pemetaan mustahik dan keterbatasan SDM. Harapannya, dengan forum seperti ini, kami mendapatkan arahan langsung sekaligus inspirasi dari Lazismu Jawa Timur.”\r\n\r\nPara narasumber menjawab pertanyaan dengan lugas dan aplikatif. Bahkan, beberapa kali diskusi berkembang menjadi sesi berbagi praktik baik antar-daerah. Hal ini memperlihatkan bahwa Lazismu tidak hanya belajar dari atas ke bawah, tetapi juga antar-sesama penggerak di tingkat daerah.\r\n\r\nForum Penguatan Bersama\r\n\r\nModerator Hendra Pornama menegaskan kembali bahwa pertemuan ini bukan sekadar seremonial, melainkan forum penguatan. “Coaching Clinic ini kita adakan untuk benar-benar membantu daerah menyelesaikan masalah, menemukan solusi, dan melahirkan terobosan. Kita ingin Lazismu semakin solid dan profesional,” tegasnya.\r\n\r\nSuasana kebersamaan semakin terasa saat para peserta sepakat untuk menindaklanjuti diskusi dengan aksi nyata di daerah masing-masing. Beberapa gagasan kolaborasi regional pun mulai mencuat, seperti pelatihan fundraising bersama, sinergi program pemberdayaan, hingga rencana membangun pusat data mustahik berbasis digital.\r\n\r\nHarapan ke Depan\r\n\r\nPertemuan yang berlangsung di jalur strategis JLS Tulungagung ini meninggalkan kesan mendalam bagi peserta. Selain mendapat ilmu dan motivasi, mereka juga merasakan semangat persaudaraan yang menguat.\r\n\r\n“Semoga kegiatan ini bisa rutin digelar. Kami merasa sangat terbantu. Kadang masalah yang kami alami di daerah ternyata juga dialami oleh Lazismu lain, dan di forum ini kita bisa saling berbagi solusi,” ujar salah satu peserta.\r\n\r\nLazismu Jawa Timur melalui Aditio Yudhono menegaskan pihaknya akan terus mendampingi Lazismu daerah. “Kami ingin Lazismu AG Raya bisa menjadi model pengelolaan zakat yang profesional, amanah, dan berdampak luas. Semua ini hanya bisa tercapai bila kita berjalan bersama,” ujarnya menutup.\r\n\r\nDengan semangat Coaching Clinic ini, Lazismu AG Raya diharapkan semakin solid dalam mengelola dana umat, sehingga manfaat zakat, infaq, dan sedekah semakin terasa bagi masyarakat luas.', '1756569347_68b31f039fb3d.png', 'Bu Rosi manager Fundraising LAZISMU JATIM sedang pemaparan', 'Muhammad Khoirun Nizam', 'sosial, lazismu Tulungagung, LAZISMU AG raya, temanamal', '2025-08-27 15:17:17', '2026-06-28 03:20:52', 'published', 125),
(12, 'opini', 'Mengapa Sedekah Jariah Begitu Istimewa? Naskah Khotbah Jumat', 'mengapa-sedekah-jariah-begitu-istimewa-naskah-khotbah-jumat', 'Sedekah jariah adalah amal yang tak berhenti bersama waktu. Pahala terus mengalir meski pelakunya telah tiada—meninggalkan jejak kebaikan yang abadi dalam masyarakat dan dicatat Allah sebagai atsar yang tak terhapuskan.\r\n\r\nOleh Dr. Aji Damanuri, M.E.I., Ketua Majelis Tarjih dan Tajdid Pimpinan Daerah Muhammadiyah Tulungagung, Dekan FEBI UIN Kiai Ageng Muhammad Besari Ponorogo', 'Temanamal.org – Naskah khotbah Jumat berjudul: Mengapa Sedekah Jariah Begitu Istimewa? selengkapnya adalah:\r\n\r\nSaudaraku sidang Jumat rahimakumullah\r\n\r\nKita sering merasakan kenikmatan ibadah saat sedang melakukannya: salat, puasa, tilawah, zikir. Pahalanya hadir seiring gerak bibir, niat, dan rukuk sujud kita.\r\n\r\nNamun, ada satu jenis amal yang bekerja “melewati” waktu: sedekah jariah. Ia tetap meneteskan pahala ketika kita pulang dari lokasi sedekah—bahkan saat kita telah tiada. Mengapa sedekah jariah begitu istimewa?\r\n\r\nAllah menggambarkan logika spiritual sedekah dengan metafora pertanian yang subur:\r\n\r\nمَثَلُ الَّذِينَ يُنْفِقُونَ أَمْوَالَهُمْ فِي سَبِيلِ اللَّهِ كَمَثَلِ حَبَّةٍ أَنْبَتَتْ سَبْعَ سَنَابِلَ فِي كُلِّ سُنْبُلَةٍ مِائَةُ حَبَّةٍ ۗ وَاللَّهُ يُضَاعِفُ لِمَنْ يَشَاءُ ۗ وَاللَّهُ وَاسِعٌ عَلِيمٌ\r\n\r\n“Perumpamaan orang-orang yang menafkahkan hartanya di jalan Allah adalah seperti sebutir benih yang menumbuhkan tujuh bulir; pada tiap bulir seratus biji. Allah melipatgandakan bagi siapa yang Dia kehendaki; dan Allah Mahaluas (karunia-Nya) lagi Maha Mengetahui.” (Al-Baqarah: 261)\r\n\r\nAyat ini bukan sekadar angka, tetapi cara pandang: satu benih sosial bisa merekah menjadi panen yang berulang. Sedekah jariah adalah air yang terus mengalir, ilmu yang terus diajarkan, fasilitas publik yang terus digunakan—semuanya menjadi “benih” yang menumbuhkan panen pahala lintas waktu.\r\n\r\nAllah juga menekankan kualitas, bukan hanya kuantitas infak:\r\n\r\nلَنْ تَنَالُوا الْبِرَّ حَتَّى تُنْفِقُوا مِمَّا تُحِبُّونَ ۚ وَمَا تُنْفِقُوا مِنْ شَيْءٍ فَإِنَّ اللَّهَ بِهِ عَلِيمٌ\r\n\r\nBaca Juga:  Bahaya Hawa Nafsu, Isi Khotbah Jumat di Ponpes Miftahul Ulum Jatinom Blitar\r\n“Kamu sekali-kali tidak akan memperoleh kebajikan (yang sempurna) sebelum kamu menafkahkan sebagian harta yang kamu cintai. Dan apa pun yang kamu nafkahkan, sungguh Allah Maha Mengetahui.” (Ali Imran: 92)\r\n\r\nTentang “jejak” amal yang tetap tercatat setelah kita tiada, Al-Qur’an menyatakan:\r\n\r\nإِنَّا نَحْنُ نُحْيِ الْمَوْتَىٰ وَنَكْتُبُ مَا قَدَّمُوا وَآثَارَهُمْ\r\n\r\n“Sesungguhnya Kamilah yang menghidupkan orang-orang mati dan Kami menuliskan apa yang telah mereka kerjakan dan jejak-jejak (pengaruh) yang mereka tinggalkan.” (Yasin: 12)\r\n\r\nSedekah jariah adalah atsar—jejak sosial—yang terus bekerja menjadi alasan turunnya pahala, bahkan ketika pelakunya telah jauh dari tempat peruntukan sedekahnya.\r\n\r\nSaudaraku sidang Jumat rahimakumullah\r\n\r\nDi tempat lain, Allah mengajarkan mentalitas “investasi ilahiah”:\r\n\r\nإِنَّ الْمُصَّدِّقِينَ وَالْمُصَّدِّقَاتِ وَأَقْرَضُوا اللَّهَ قَرْضًا حَسَنًا يُضَاعَفُ لَهُمْ وَلَهُمْ أَجْرٌ كَرِيمٌ\r\n\r\n“Sesungguhnya orang-orang laki-laki yang bersedekah dan perempuan yang bersedekah serta yang meminjamkan kepada Allah pinjaman yang baik, (pahalanya) dilipatgandakan bagi mereka; dan bagi mereka pahala yang mulia.” (Al-Hadid: 18)\r\n\r\nBahasa “meminjamkan kepada Allah” adalah retorika ketuhanan yang menenteramkan. Harta seakan keluar dari kepemilikan kita, tetapi sejatinya ia disimpan oleh Zat yang Mahakuasa untuk dikembalikan berlipat.\r\n\r\nSaudaraku sidang Jumat rahimakumullah\r\n\r\nLandasan utama sedekah jariah datang dari hadis sahih:\r\n\r\nإِذَا مَاتَ ابْنُ آدَمَ انْقَطَعَ عَمَلُهُ إِلَّا مِنْ ثَلَاثٍ: صَدَقَةٍ جَارِيَةٍ، أَوْ عِلْمٍ يُنْتَفَعُ بِهِ، أَوْ وَلَدٍ صَالِحٍ يَدْعُو لَهُ\r\n\r\n“Apabila manusia meninggal dunia, terputuslah (pahala) amalnya kecuali dari tiga perkara: sedekah jariah, ilmu yang bermanfaat, atau anak saleh yang mendoakannya.” (HR. Muslim)\r\n\r\nHadis lain mempertebal motivasi:\r\n\r\nاتَّقُوا النَّارَ وَلَوْ بِشِقِّ تَمْرَةٍ\r\n\r\n“Lindungilah diri kalian dari api neraka walau hanya dengan (sedekah) setengah butir kurma.” (Mutafakunalaih)\r\n\r\n\r\nمَا نَقَصَتْ صَدَقَةٌ مِنْ مَالٍ\r\n\r\n“Sedekah tidak akan mengurangi harta.” (H.R. Muslim)\r\n\r\nSecara empiris, kita mungkin merasa berkurang ketika memberi. Namun sabda Nabi menata ulang logika kita: berkurang di kas, berlipat di pahala; berkurang di dompet, bertambah di jiwa; dan di tingkat sosial, sedekah menggerakkan roda kebaikan yang kembali kepada pemberi dalam bentuk kepercayaan, dukungan, dan jaringan sosial.\r\n\r\nSaudaraku sidang Jumat rahimakumullah\r\n\r\nPraktik puncak sedekah jariah dalam fikih adalah wakaf: menahan pokok harta agar manfaatnya terus mengalir. Diriwayatkan bahwa Umar bin Khattab ra. mendapatkan tanah di Khaibar; lalu Rasulullah saw. bersabda:\r\n\r\nإِنْ شِئْتَ حَبَسْتَ أَصْلَهَا وَتَصَدَّقْتَ بِهَا\r\n\r\n“Jika engkau mau, tahanlah pokoknya dan sedekahkan (hasil)nya.” (H.R. Bukhari)\r\n\r\nInilah prinsip habs al-ashl wa tasbil al-manfa‘ah—pokok ditahan, manfaat disalurkan. Dalam sejarah Islam, wakaf menopang masjid, madrasah, rumah sakit, perpustakaan, jalan, jembatan, hingga tempat singgah musafir. Dengan bahasa modern, wakaf adalah mekanisme pembiayaan publik berbasis iman: jaring pengaman sosial dan akselerator peradaban yang tahan krisis.\r\n\r\nSaudaraku sidang Jumat rahimakumullah\r\n\r\nKuncinya, sedekah jariah wakaf adalah pokoknya bertahan, manfaatnya mengalir.\r\n\r\nMengapa Pahalanya Terus Mengalir?\r\n\r\nDari perspektif maqashid al-syariah, sedekah jariah melindungi lima tujuan besar:\r\n\r\nHifzh al-din (agama): menopang dakwah dan pendidikan iman.\r\n\r\nHifzh al-nafs (jiwa): layanan kesehatan, air bersih, pangan.\r\n\r\nHifzh al-‘aql (akal): beasiswa, perpustakaan, riset.\r\n\r\nHifzh al-nasl (keturunan): lingkungan bersih, rumah aman, gizi baik.\r\n\r\nHifzh al-mal (harta): tata kelola dana umat yang produktif dan transparan.\r\n\r\nDari sisi ekonomi, sedekah jariah menciptakan public goods (barang publik) dan positive externalities (manfaat eksternal). Misalnya, sebuah sumur wakaf mengurangi biaya kesehatan (air bersih) dan waktu tempuh, meningkatkan produktivitas, dan menumbuhkan ekonomi lokal.\r\n\r\nDari sosiologi, sedekah jariah memperkuat modal sosial (social capital): kepercayaan, norma saling bantu, dan jejaring.\r\n\r\nDari psikologi, memberi secara berkelanjutan menumbuhkan makna hidup (meaning in life), menurunkan stres, dan meningkatkan kesejahteraan subjektif.\r\n\r\nDari antropologi, sedekah jariah menata pertukaran hadiah (gift exchange) ke level institusional: bukan hanya memberi kepada individu, tetapi menghadirkan infrastruktur kebaikan lintas generasi.\r\n\r\nKhotbah Kedua\r\n\r\nSaudaraku sidang Jumat rahimakumullah,\r\n\r\nTiga pilar agar sedekah jariah benar-benar jariah:\r\n\r\nKeikhlasan dan kualitas\r\nAllah menegaskan agar yang diberikan adalah yang baik dan dicintai (Ali Imran: 92). Jangan jadikan sedekah sebagai tempat pembuangan barang tak layak. Niatkan lillah, jauh dari riya.\r\n\r\nRelevansi dan keberlanjutan\r\nPilih program yang menjawab masalah nyata: akses air, pendidikan dasar, literasi digital, ketahanan pangan, ekonomi mikro. Pastikan modelnya berkelanjutan—ada perawatan, ada SDM, ada skema pendanaan pasca pembangunan.\r\n\r\nAmanah dan transparansi\r\nRasulullah saw. menekankan amanah dalam harta. Di masa kini, dokumentasi yang tertib, audit syariah, pelaporan terbuka, dan partisipasi warga memperkuat keberlanjutan. Transparansi bukan sekadar administratif; ia menjaga keberkahan.\r\n\r\nSaudaraku sidang Jumat rahimakumullah\r\n\r\nSedekah jariah bukan panggung untuk mengabadikan nama, melainkan wahana untuk mengabadikan manfaat. Nama mungkin pudar, tetapi atsar—jejak manfaat—tetap ditulis oleh Allah (Yasin: 12). Karena itu, ukuran sukses sedekah bukan seberapa besar plakatnya, melainkan seberapa lama ia terus menolong orang, menumbuhkan ilmu, dan menyelamatkan hidup.\r\n\r\nSemoga Allah menuntun kita menanam benih yang tidak hanya tumbuh untuk diri, tetapi juga menaungi banyak jiwa, benih yang panennya terus tiba bahkan setelah kita beristirahat di tanah. Amin.\r\n\r\nNaskah ini di ambil dari https://tagar.co/mengapa-sedekah-jariah-begitu-istimewa-naskah-khotbah-jumat/', '1757860554_6889104A-5FAC-435D-A9C1-CE2C8C75561D.jpeg', 'Foto Aji Damanuri Diambil  dari tagar.co', 'Muhammad Khoirun Nizam, S.Sos', 'Ajidamanuri, Naskah Khotbah, Khotbah Jumat', '2025-09-14 14:35:54', '2026-06-28 09:11:12', 'published', 215),
(13, 'berita', 'Kolaborasi Edukasi dan E-Sport: PPL UIN SATU Tulungagung Adakan Tournament Mobile Legends', 'kolaborasi-edukasi-dan-e-sport-ppl-uin-satu-tulungagung-adakan-tournament-mobile-legends', 'Praktik Pengalaman Lapangan (PPL) UIN Sayyid Ali Rahmatullah (SATU) Tulungagung menghadirkan inovasi kegiatan dengan menggelar Tournament Mobile Legends yang berlangsung meriah. Acara ini sukses menarik perhatian mahasiswa sekaligus komunitas pecinta e-sport, serta mendapat dukungan penuh dari Lazismu Tulungagung sebagai sponsor utama.', 'temanamal.org- Praktik Pengalaman Lapangan (PPL) UIN Sayyid Ali Rahmatullah (SATU) Tulungagung menghadirkan nuansa baru dalam kegiatan mahasiswa dengan menggelar Tournament Mobile Legends. Acara ini tidak hanya meriah, tetapi juga menjadi ajang kolaborasi antara dunia edukasi dan e-sport dengan dukungan penuh dari Lazismu Tulungagung.\r\n\r\nTurnamen ini menjadi ajang positif bagi mahasiswa untuk menyalurkan minat dan bakat di bidang e-sport. Sejumlah tim peserta berkompetisi dengan semangat tinggi, mempertontonkan strategi permainan, kerja sama tim, hingga kemampuan individu yang memukau. Jalannya pertandingan berlangsung sengit sejak babak awal hingga partai final, menambah keseruan sekaligus semangat sportivitas di kalangan peserta.\r\n\r\nPanitia PPL UIN SATU Tulungagung menjelaskan bahwa tujuan dari turnamen ini tidak hanya untuk hiburan semata, tetapi juga memberikan ruang aktualisasi diri bagi mahasiswa di tengah perkembangan era digital. “E-sport saat ini bukan sekadar permainan, tetapi sudah menjadi cabang kompetisi yang bisa melatih kedisiplinan, komunikasi, serta kerja sama tim. Inilah nilai edukasi yang ingin kami hadirkan melalui kegiatan ini,” ujar salah satu panitia.\r\n\r\nLazismu Tulungagung, sebagai sponsor utama, menyampaikan dukungan penuh terhadap kegiatan kreatif mahasiswa. Menurutnya, kegiatan seperti ini mampu memberikan dampak positif dan menjadi sarana pemberdayaan generasi muda. Dukungan Lazismu bukan hanya dalam bentuk sponsorship, tetapi juga motivasi agar mahasiswa mampu berkarya sekaligus berprestasi.\r\n\r\nSuasana turnamen semakin semarak saat penyerahan hadiah kepada tim pemenang. Kebanggaan terpancar dari wajah para juara yang berhasil membuktikan kemampuan mereka di panggung e-sport kampus. Panitia berharap kegiatan ini bisa menjadi agenda rutin yang tidak hanya menghibur, tetapi juga membangun karakter mahasiswa yang sportif, kreatif, dan kolaboratif.\r\n\r\nDengan adanya Tournament Mobile Legends ini, PPL UIN SATU Tulungagung membuktikan bahwa dunia pendidikan dapat berkolaborasi dengan dunia digital untuk mencetak generasi yang cerdas, berdaya saing, dan tetap menjunjung tinggi nilai kebersamaan.', '1758424900_68cf6f44c15a9.jpeg', 'Pemenang tornament', 'Muhammad Khoirun Nizam, S.Sos', 'Education dakwah, Anak muda', '2025-09-21 03:21:42', '2026-06-28 06:47:07', 'published', 122),
(14, 'berita', 'Back to Masjid: Lazismu Tulungagung dan Zendo Bersihkan Masjid Al-Falah Desa Simo', 'back-to-masjid-lazismu-tulungagung-dan-zendo-bersihkan-masjid-al-falah-desa-simo', 'temanamal.org - Mengusung semangat kepedulian dan kebersamaan, Lazismu Tulungagung berkolaborasi dengan Zendo Tulungagung menggelar kegiatan Back to Masjid berupa aksi bersih-bersih masjid. Kegiatan ini berlangsung di Masjid Al-Falah, Desa Simo, Kecamatan Kedungwaru, Ahad, 21 September 2025 , dengan melibatkan relawan muda dan masyarakat sekitar.', 'Sejak pagi para relawan sudah hadir dengan perlengkapan kebersihan. Mereka bahu-membahu membersihkan area masjid, mulai dari menyapu dan mengepel lantai, mencuci karpet, hingga membersihkan kaca jendela dan pintu masjid. Terlihat suasana penuh semangat dan kekompakan saat para relawan bekerja sama menjaga kebersihan rumah ibadah tersebut.\r\n\r\nDirektur Lazismu Tulungagung menyampaikan bahwa kegiatan ini merupakan bagian dari program Back to Masjid yang diinisiasi untuk mengajak masyarakat lebih peduli terhadap kebersihan dan kenyamanan masjid. “Masjid bukan hanya tempat ibadah, tetapi juga pusat kegiatan sosial, pendidikan, dan dakwah. Maka dari itu, menjaga kebersihan masjid adalah bagian dari menjaga marwah umat Islam,” ujarnya.\r\n\r\nHal senada juga disampaikan Suyanto perwakilan Zendo Tulungagung. Ia menegaskan bahwa kolaborasi ini adalah bukti nyata sinergi antara lembaga sosial dan komunitas yang bergerak di bidang kebersihan. “Kami ingin menghadirkan masjid yang bersih, sehat, dan nyaman, sehingga jamaah bisa beribadah dengan tenang dan penuh kekhusyukan,” katanya.\r\n\r\nMasyarakat Desa Simo turut menyambut baik program ini. Sejumlah jamaah bahkan ikut membantu dalam proses pembersihan masjid. Mereka mengapresiasi langkah Lazismu dan Zendo yang tidak hanya fokus pada kegiatan sosial kemanusiaan, tetapi juga memberikan perhatian khusus terhadap rumah ibadah.\r\n\r\n“Dengan adanya kegiatan ini, kami sebagai warga merasa sangat terbantu. Masjid jadi lebih bersih dan nyaman. Semoga kegiatan seperti ini terus berlanjut dan bisa dilakukan di masjid-masjid lain,” ungkap salah satu takmir Masjid Al-Falah.\r\n\r\nProgram Back to Masjid ini juga menjadi momentum untuk menumbuhkan kembali semangat gotong royong dan kepedulian bersama. Melalui kegiatan sederhana seperti bersih-bersih masjid, tercermin nilai kebersamaan, kepedulian, sekaligus dakwah bil hal yang sangat dibutuhkan dalam kehidupan bermasyarakat.\r\n\r\nLazismu Tulungagung berkomitmen akan terus mendorong program-program pemberdayaan umat, salah satunya melalui kegiatan kebersihan masjid yang secara rutin akan dilaksanakan di berbagai wilayah. Dengan demikian, masjid dapat menjadi pusat kegiatan keagamaan dan sosial yang benar-benar nyaman, bersih, dan memberi keberkahan bagi jamaahnya.', '1758426367_68cf74ff55c9b.jpeg', 'Foto sedang bersih bersih', 'Muhammad Khoirun Nizam, S.Sos', 'BackToMasjid, LazismuTulungagung, ZendoTulungagung, BersihBersihMasjid, MasjidAlFalah, Kedungwaru, DesaSimo, GerakanPeduliMasjid', '2025-09-21 03:46:09', '2026-06-28 04:39:06', 'published', 139),
(15, 'berita', 'Lazismu AG Raya Gelar Konsolidasi di Bercakap Kopi Kediri: Satukan Visi, Perkuat Gerakan Filantropi', 'lazismu-ag-raya-gelar-konsolidasi-di-bercakap-kopi-kediri-satukan-visi-perkuat-gerakan-filantropi', 'temanamal.org – Menguatkan barisan dan merapikan langkah gerakan menjadi fokus utama pertemuan Lazismu AG Raya yang digelar di Bercakap Kopi, Kabupaten Kediri. Dengan mengangkat tema “Penguatan Internal Lazismu AG Raya”, pertemuan ini menghadirkan para pengurus Lazismu dari berbagai daerah se-wilayah AG Raya. Suasana pertemuan tampak hangat, menggambarkan semangat persaudaraan dan tekad kuat untuk memajukan gerakan filantropi Muhammadiyah.', 'Hadir dalam pertemuan tersebut Manajer Area Lazismu Wilayah Jawa Timur, Agus Lukman, yang didapuk sebagai pembicara utama. Dalam sambutannya, ia menyampaikan apresiasi terhadap semangat kolaboratif Lazismu di wilayah AG Raya yang dinilai memiliki potensi besar dalam penguatan gerakan dakwah sosial.\r\n\r\n“Lazismu adalah amanah umat. Maka setiap langkah kerja kita harus berangkat dari kesadaran bahwa yang kita jalankan ini adalah bagian dari dakwah, bukan sekadar kegiatan sosial biasa. Di sinilah pentingnya penguatan internal agar kita punya arah yang jelas, ritme yang terukur, dan tim yang solid,” jelas Agus Lukman.\r\n\r\nDalam suasana diskusi yang santai namun serius, satu per satu perwakilan dari Lazismu daerah menyampaikan laporan perkembangan sekaligus tantangan di lapangan. Beberapa daerah berbagi pengalaman tentang bagaimana menggerakkan relawan di tingkat ranting dan majelis taklim, sementara daerah lain menyoroti pentingnya inovasi penggalangan dana melalui platform digital sebagai respons terhadap perubahan pola donasi masyarakat.\r\n\r\nLazismu Tulungagung, misalnya, menyampaikan bahwa pendekatan komunitas menjadi strategi efektif dalam membangun basis donatur tetap. Sementara Lazismu Kediri mengungkapkan perlunya membangun budaya administrasi dan dokumentasi yang rapi agar setiap program yang dijalankan memiliki jejak yang bisa dipertanggungjawabkan secara publik.\r\n\r\n“Kita ini membawa nama Muhammadiyah. Maka setiap kegiatan bukan hanya harus bermanfaat, tetapi juga harus tertata, terdokumentasi, dan bisa dikomunikasikan dengan baik kepada umat,” ujar salah satu pengurus dalam forum.\r\n\r\nDalam arahannya, Agus Lukman menekankan tiga pilar penting yang harus diperkuat: struktur kelembagaan, kualitas sumber daya manusia, dan koordinasi lintas daerah yang berkelanjutan. Menurutnya, tanpa pembenahan internal yang serius, sebanyak apapun program yang dijalankan akan sulit memberikan dampak jangka panjang.\r\n\r\n“Lazismu daerah harus mulai berani memetakan potensi, menetapkan indikator kinerja, dan membangun pola komunikasi rutin. Jangan hanya bergerak kalau ada momentum, tetapi bangun sistem agar kerja kita berkesinambungan,” tegasnya.\r\n\r\nMomentum ini tidak hanya menjadi ajang konsolidasi formal, tetapi juga ruang memperkuat kedekatan emosional antar-pengurus. Suasana kekeluargaan terlihat jelas sepanjang pertemuan. Beberapa pengurus tampak berdiskusi di luar agenda utama, membahas kemungkinan sinergi program lintas kabupaten, terutama dalam isu-isu kemanusiaan dan pemberdayaan ekonomi.\r\n\r\nMenariknya, pertemuan ini juga melahirkan kesepakatan awal untuk membangun forum komunikasi Lazismu AG Raya yang lebih sistematis. Forum ini diharapkan menjadi kanal koordinasi, berbagi praktik baik, sekaligus sebagai media kontrol bersama agar gerakan Lazismu di wilayah eks-Karesidenan Kediri semakin relevan dan berdaya.\r\nDi akhir sesi, Agus Lukman kembali menekankan bahwa kekuatan Lazismu bukan pada besar kecilnya dana yang dihimpun, tetapi pada ketepatan strategi dan kepercayaan publik.\r\n\r\n“Kalau Lazismu dipercaya umat, maka gerakan ini akan mengalir dengan sendirinya. Tapi kepercayaan itu tidak datang tiba-tiba. Ia dibangun dari tata kelola, akuntabilitas, dan sikap rendah hati dalam melayani,” tutupnya.\r\nPertemuan ditutup dengan doa dan semangat baru. Para peserta meninggalkan ruangan dengan wajah optimis, seolah membawa komitmen yang sama: bahwa Lazismu AG Raya harus menjadi contoh gerakan filantropi yang tidak hanya aktif bergerak, tetapi juga kokoh secara kelembagaan dan berkarakter dakwah.', '1761539984_68fef7901c56d.jpg', 'sesi obrolan Lazismu AG Raya', 'Muhammad Khoirun Nizam', '#sosial, #lazismu Tulungagung, #LAZISMU AG raya, #temanamal', '2025-10-09 02:55:48', '2026-06-26 03:13:01', 'published', 118),
(16, 'berita', 'Penguatan Lazismu AG Raya: Adityo Yudhono, S.E. Paparkan Hasil Keputusan Musykerwil sebagai Arah Baru Filantropi Berkemajuan', 'lazismu-ag-raya-gelar-konsolidasi-di-bercakap-kopi-kediri-satukan-visi-perkuat-gerakan-filantropi-1', 'temanamal.org - Suasana penuh semangat dan kekeluargaan terasa kuat dalam Pertemuan Lazismu Se-AG Raya yang digelar di Bercakap Kopi, Kabupaten Kediri, Rabu (09/10/2025). Pertemuan ini menjadi momentum penting untuk mengonsolidasikan gerakan filantropi Muhammadiyah di kawasan eks-Karesidenan Kediri, menghadirkan perwakilan dari Lazismu Tulungagung, Kediri, Blitar, Trenggalek, dan Nganjuk.', 'Sorotan utama acara ini adalah pemaparan strategis yang disampaikan oleh Adityo Yudhono, S.E., perwakilan Lazismu Wilayah Jawa Timur. Dengan gaya komunikatif dan sistematis, ia menyajikan hasil keputusan Musyawarah Kerja Wilayah (Musykerwil) Lazismu Jawa Timur yang menjadi arah pijakan gerakan Lazismu ke depan.\r\n\r\nDalam pemaparannya, Adityo Yudhono, S.E. menegaskan bahwa Musykerwil tidak hanya menghasilkan dokumen keputusan, tetapi peta jalan gerakan yang harus diterjemahkan menjadi program nyata di daerah.\r\n Ia menyampaikan bahwa fokus utama Lazismu Jawa Timur tahun ini adalah penguatan data, digitalisasi layanan zakat, dan percepatan program pemberdayaan berbasis komunitas.\r\n“Kita tidak boleh hanya bergerak secara manual. Lazismu harus memiliki basis data yang akurat, sistem digital yang rapi, dan narasi yang progresif agar masyarakat melihat Lazismu bukan sekadar penyalur zakat, tetapi sebagai penggerak perubahan,” tegas Adityo Yudhono, S.E.\r\n\r\nSelain digitalisasi, Musykerwil juga menekankan pentingnya membangun identitas pelayanan Lazismu yang memuliakan penerima manfaat. Menurutnya, keunggulan Lazismu bukan pada besarnya dana yang dihimpun, tetapi pada cara Lazismu memanusiakan manusia dalam setiap program. “Kita hadir bukan hanya memberi bantuan, tapi menyalakan harapan,” lanjutnya.\r\n\r\nPada sesi diskusi, Adityo Yudhono, S.E. juga menyampaikan bahwa Musykerwil menugaskan Lazismu daerah untuk memperkuat kolaborasi lintas sektor, baik dengan pemerintah daerah, komunitas lokal, maupun jejaring filantropi lain yang memiliki visi sejalan. Sinergi ini dinilai penting untuk menghadirkan program yang lebih berdampak dan berkelanjutan.\r\nForum pertemuan menjadi ruang saling belajar antar daerah. Masing-masing Lazismu kabupaten menyampaikan progres program dan tantangan di lapangan. Ada daerah yang sudah kuat dalam pengembangan UMKM binaan, ada yang fokus pada pendidikan dan literasi zakat, sementara daerah lain unggul dalam respons sosial kemanusiaan. Dari situ muncul kesadaran bahwa sharing pengalaman dan penguatan jejaring internal adalah kebutuhan mendesak untuk mempercepat gerak gerakan zakat berkemajuan di AG Raya.\r\n\r\nPara peserta juga menyepakati bahwa narasi publik Lazismu harus diperkuat. Bukan hanya melaporkan kegiatan, tetapi menghidupkan kesadaran masyarakat bahwa zakat dan infak memiliki energi perubahan yang dahsyat jika dikelola secara profesional dan visioner.\r\n\r\nMenutup sesi, Adityo Yudhono, S.E. mengajak seluruh perwakilan Lazismu AG Raya untuk menjadikan hasil Musykerwil sebagai energi baru pengabdian. Ia menegaskan bahwa Lazismu memiliki potensi besar untuk menjadi motor kemandirian umat, asalkan penguatan internal berjalan seimbang dengan inovasi program.\r\n“Lazismu bukan hanya lembaga amal, tetapi gerakan perubahan. Mari kita jaga militansi, tata kelola, dan semangat kolaborasi agar Lazismu AG Raya bisa menjadi contoh model gerakan zakat yang mencerahkan,” ujarnya.\r\n\r\nPertemuan ditutup dengan komitmen bersama untuk menindaklanjuti hasil Musykerwil dengan langkah konkret di daerah masing-masing. Dengan semangat Ikhlas Memberi untuk Negeri, Lazismu AG Raya siap melanjutkan kerja-kerja kemanusiaan dan pemberdayaan dengan lebih solid, terarah, dan berkemajuan.', '1761539945_68fef7693252f.jpg', 'pemaparan oleh pak adit', 'Muhammad Khoirun Nizam', '#sosial, #lazismu Tulungagung, #LAZISMU AG raya, #temanamal', '2025-10-09 03:23:41', '2026-06-25 20:14:09', 'published', 117),
(18, 'opini', 'BankZiska: Gerakan Zakat Produktif untuk Memerdekakan Ekonomi Umat', 'bankziska-gerakan-zakat-produktif-untuk-memerdekakan-ekonomi-umat', 'temanamal.org - Di banyak sudut pasar dan gang-gang kecil Tulungagung, para pelaku usaha mikro berjuang mempertahankan hidup di tengah tekanan ekonomi dan jeratan hutang berbunga. Mereka bukan tidak bekerja keras, tetapi sistem sering kali tidak berpihak. Di saat seperti inilah, zakat tidak cukup hanya dibagikan, ia harus bergerak lebih jauh: membebaskan. Dan dari kesadaran inilah, lahir BankZiska—ikhtiar Lazismu Tulungagung untuk menjadikan zakat sebagai kekuatan produktif yang memerdekakan umat secara ekonomi.', 'Zakat selama ini sering dipahami hanya sebagai bantuan sesaat, diberikan untuk memenuhi kebutuhan harian para mustahik tanpa meninggalkan dampak jangka panjang. Namun di tengah tantangan ekonomi modern, Lazismu Tulungagung mengambil langkah berbeda dengan mendorong lahirnya zakat produktif sebagai strategi kemandirian. Melalui program BankZiska (BANtuan Keuangan dari dana Zakat, Infaq, Shodaqoh, dan dana Sosial Keagamaan lainnya), Lazismu menghadirkan solusi nyata agar zakat tidak hanya dibagikan, tetapi diputar menjadi kekuatan ekonomi pemberdaya. BankZiska tidak bekerja seperti lembaga keuangan konvensional, melainkan menerapkan sistem al-Qardhul Hasan, yaitu pinjaman tanpa bunga, tanpa denda, dan tanpa biaya tambahan—sebuah pendekatan yang memuliakan mustahik dan menjaga keberkahan harta umat.\r\nRealitas di lapangan menunjukkan bahwa banyak pelaku usaha kecil di Tulungagung—dari pedagang pasar, penjual makanan rumahan, hingga pengrajin lokal—sering terpaksa mengambil pinjaman berbunga tinggi dari rentenir karena kebutuhan modal yang mendesak. Mereka bekerja keras, tetapi tetap terjebak dalam lingkar hutang yang melemahkan. Di sinilah BankZiska hadir bukan hanya sebagai penyedia modal, tetapi jalan keluar dari sistem ekonomi yang menindas. Dengan pendekatan zakat produktif, Lazismu tidak hanya menolong secara materi, tetapi membangkitkan rasa percaya diri, martabat, dan harapan baru bahwa umat bisa mandiri tanpa harus tunduk pada praktik yang merugikan.\r\nLebih dari sekadar penyaluran dana, BankZiska memiliki potensi besar untuk membangun ekosistem pemberdayaan jika dikaitkan dengan jaringan besar Muhammadiyah. Majelis ekonomi, masjid, amal usaha pendidikan, komunitas pemuda, hingga gerakan perempuan mampu menjadi simpul yang menyatukan modal, pendampingan usaha, edukasi spiritual, dan akses pasar. Jika ini dijalankan secara konsisten, zakat tidak akan berhenti di tangan penerima, tetapi berputar, tumbuh, dan melahirkan para pelaku usaha baru yang berdaya dan bermartabat. Ketika para penerima modal mampu mandiri dan berkembang, bukan mustahil suatu saat mereka kembali bukan sebagai mustahik, tetapi sebagai muzakki. Inilah transformasi sosial yang menjadi cita-cita tertinggi zakat produktif.\r\nBankZiska bukan sekadar program keuangan, tetapi momentum dakwah ekonomi. Sebab membebaskan umat dari jeratan kemiskinan struktural adalah bagian dari jihad sosial yang harus diperjuangkan bersama. Dari Tulungagung, Lazismu telah menyalakan obor perubahan ini. Kini, tugas kita adalah memastikan nyala itu terus menyebar, menguat, dan menjadi gerakan kemandirian ekonomi umat yang membanggakan.', '1761539910_68fef746cdc0e.png', 'sandbox:/mnt/data/A_digital_illustration_depicts_an_economic_empower.png', 'Muhammad Khoirun Nizam', '#sosial, #lazismu Tulungagung, #LAZISMU AG raya, #temanamal', '2025-10-16 01:14:16', '2026-06-22 10:41:12', 'published', 152),
(19, 'berita', 'Seminar Wawasan Kebangsaan: Upaya Tingkatkan Literasi Gerakan Moderasi dan Tangkal Isu Radikalisme', 'seminar-wawasan-kebangsaan-upaya-tingkatkan-literasi-gerakan-moderasi-dan-tangkal-isu-radikalisme', 'temanamal.org – Suasana Aula yang tertata rapi dengan dominasi hijau dan kuning dari seragam para peserta tampak memenuhi ruangan dalam kegiatan Seminar Wawasan Kebangsaan yang diselenggarakan oleh Pimpinan … (silakan sebutkan ortom/lembaga penyelenggara/isian sesuai kebutuhan). Kegiatan ini mengusung tema “Peran Perempuan dalam Menangkal Isu-Isu Radikalisme dan Intoleransi terhadap Kelompok Tertentu” dan diikuti oleh puluhan peserta dari unsur organisasi otonom Muhammadiyah.', 'Acara dibuka dengan sambutan resmi dari panitia pelaksana. Dalam sambutannya, perwakilan panitia menyampaikan bahwa kegiatan ini menjadi bagian dari ikhtiar mencerdaskan umat, khususnya dalam memahami isu-isu kebangsaan yang akhir-akhir ini sering dipelintir di media sosial.\r\n\r\n“Literasi kebangsaan harus dibangun dari ruang-ruang kaderisasi semacam ini. Dengan pemahaman yang lurus, kita berharap warga persyarikatan mampu menjadi penyejuk di tengah derasnya isu radikalisme dan intoleransi,” ujarnya.\r\n\r\nSeminar ini menghadirkan narasumber dari kalangan akademisi dan praktisi kebangsaan. Dalam pemaparannya, narasumber menjelaskan bahwa radikalisme tidak selalu identik dengan simbol agama tertentu. Menurutnya, radikalisme justru muncul ketika seseorang tidak mampu memandang perbedaan secara proporsional.\r\n\r\n“Radikalisme bisa tumbuh dari sikap merasa paling benar. Muhammadiyah sejak awal berdiri telah mengajarkan moderasi, bukan dengan istilah, tetapi dengan praktik nyata: menebar rahmat, bukan kebencian,” tegas narasumber.\r\n\r\nPeserta tampak antusias mengikuti sesi diskusi. Beberapa peserta mengajukan pertanyaan seputar bagaimana perempuan Muhammadiyah dapat mengambil peran strategis dalam menangkal narasi intoleransi. Pertanyaan tersebut dijawab dengan lugas oleh narasumber.\r\n“Perempuan adalah pusat pendidikan pertama dalam keluarga. Jika ibu memiliki wawasan kebangsaan yang mencerahkan, maka keluarga akan tumbuh dengan karakter cinta damai dan tidak mudah terprovokasi. Ini adalah dakwah yang sesungguhnya,” jelasnya.\r\n\r\nTidak hanya berhenti pada tataran teori, seminar ini juga memberikan contoh konkret mengenai cara menyikapi perbedaan di tengah masyarakat majemuk. Peserta diajak memahami bahwa dakwah berkemajuan bukan hanya tentang menyampaikan kebenaran, tetapi juga menghadirkan keteduhan.\r\n\r\nSuasana keakraban terlihat ketika moderator membuka sesi refleksi. Para peserta diminta menyampaikan kesan dan rencana tindak lanjut setelah mengikuti seminar. Seorang peserta mengungkapkan rasa syukurnya bisa mengikuti kegiatan ini.\r\n\r\n“Kami merasa mendapatkan bekal penting. Terkadang kami aktif di komunitas, tapi kurang memahami narasi kebangsaan secara komprehensif. Kegiatan seperti ini sangat dibutuhkan untuk memperkuat sikap moderat warga persyarikatan,” tuturnya.\r\n\r\nMenutup acara, panitia mengajak seluruh peserta untuk terus menyebarkan semangat Islam berkemajuan dengan narasi persatuan dan persaudaraan. Mereka berharap kegiatan semacam ini bisa berlanjut dan menjangkau lapisan masyarakat yang lebih luas.\r\nDengan terselenggaranya seminar ini, Muhammadiyah dan Aisyiyah kembali menegaskan komitmennya sebagai gerakan dakwah yang mencerahkan dan menjadi pelopor dalam menjaga harmoni kehidupan berbangsa.', '1761539877_68fef7258a083.jpg', 'foto kegiatan acara seminar', 'Muhammad Khoirun Nizam', '#WawasanKebangsaan,#MuhammadiyahBerkemajuan, #ModerasiBeragama,  #PerempuanMuhammadiyah, #IslamBerkemajuan, #Radikalisme, #AntiIntoleransi, #DakwahPencerahan, #LiterasiKebangsaan, #PWMUTulungagung, #OrtOMMuhammadiyah, #GerakanPencerahan,', '2025-10-18 02:29:11', '2026-06-28 02:10:10', 'published', 118),
(20, 'opini', 'Dari Kotak Amal ke Klik Digital: Transformasi ZISWAF bersama temanamal.org LAZISMU Tulungagung', 'dari-kotak-amal-ke-klik-digital-transformasi-ziswaf-bersama-temanamal-org-lazismu-tulungagung', 'Di era serba digital, beramal tak lagi harus menunggu kotak infak berkeliling atau datang ke kantor lembaga zakat. Kini, cukup lewat genggaman tangan, setiap muslim bisa menunaikan zakat, infak, sedekah, dan wakaf dengan mudah. Inovasi ini diwujudkan oleh LAZISMU Tulungagung melalui platform Teman Amal — sebuah website donasi digital yang menghadirkan efisiensi, transparansi, dan jangkauan luas bagi para dermawan masa kini.', 'temanamal.org - Perkembangan teknologi digital telah membawa perubahan besar dalam berbagai aspek kehidupan, termasuk dalam pengelolaan zakat, infak, sedekah, dan wakaf (ZISWAF). Kini, aktivitas filantropi umat tidak lagi terbatas pada kotak amal masjid atau kegiatan penggalangan dana manual. Inovasi digital menjadikan proses donasi lebih mudah, cepat, transparan, dan bisa diakses dari mana saja. Salah satu contoh nyata penerapan digitalisasi ZISWAF yang berhasil di tingkat daerah adalah LAZISMU Tulungagung melalui platform digitalnya, website Teman Amal (temanamal.org).\r\n\r\nMelalui situs Teman Amal, masyarakat dapat menunaikan ZISWAF hanya dengan beberapa klik. Tersedia berbagai pilihan program seperti Sedekah umum, Peduli Guru, Beasiswa mentari dan sangsurya, jumat berkah, dan masih bayak program lainya yang bisa di pilih. Donatur cukup memilih program yang ingin didukung, menentukan nominal, dan melakukan pembayaran secara digital. Kemudahan ini menjadi bukti nyata bahwa efisiensi dalam pengelolaan ZISWAF kini bisa dirasakan langsung oleh masyarakat.\r\n\r\nEfisiensi tersebut juga tampak dari sisi internal lembaga. Sistem di Teman Amal secara otomatis mencatat setiap transaksi, sehingga meminimalkan kesalahan pencatatan dan mempercepat proses administrasi. Tim LAZISMU Tulungagung kini dapat memusatkan perhatian pada pemberdayaan masyarakat dan pengembangan program sosial, bukan lagi sekadar pengumpulan dan pencatatan donasi manual.\r\n\r\nAspek transparansi juga menjadi keunggulan utama dari digitalisasi ini. Di situs Teman Amal, setiap program menampilkan nominal dana yang sudah terkumpul dan dokumentasi kegiatan yang sudah berjalan. Donatur dapat memantau progres penyaluran donasi, melihat foto kegiatan, bahkan membaca laporan singkat penggunaan dana. Contohnya, pada program “Sedekah Jumat”, ditampilkan total donasi yang masuk serta laporan distribusi kepada masyarakat penerima manfaat. Keterbukaan ini menumbuhkan kepercayaan publik, sekaligus menjadi bukti akuntabilitas LAZISMU Tulungagung dalam mengelola amanah umat.\r\n\r\nSelain efisiensi dan transparansi, digitalisasi melalui Teman Amal juga memperluas jangkauan ZISWAF. Dahulu, penghimpunan dana LAZISMU Tulungagung terbatas pada jaringan lokal dan donatur tetap. Kini, berkat platform daring, masyarakat dari luar daerah bahkan luar negeri dapat turut berkontribusi. Diaspora Muhammadiyah yang berada di Malaysia atau Timur Tengah bisa langsung menyalurkan zakat dan infaknya tanpa harus datang ke kantor layanan.\r\n\r\nDigitalisasi Teman Amal bukan sekadar transformasi teknologi, tetapi juga transformasi budaya beramal. LAZISMU Tulungagung mampu mengedukasi masyarakat agar beradaptasi dengan perubahan zaman, tanpa meninggalkan nilai spiritual dan keikhlasan dalam berzakat dan bersedekah.\r\n\r\nDengan langkah progresif ini, Teman Amal menjadi bukti nyata bahwa digitalisasi ZISWAF adalah jalan menuju tata kelola zakat yang lebih modern, amanah, dan berdampak luas. Teknologi bukanlah ancaman bagi nilai-nilai filantropi Islam, melainkan wasilah (perantara) untuk memperluas kebermanfaatan dan mempercepat terwujudnya kesejahteraan umat.', '1763094761_6916b0e9cdd5b.png', 'ai gambar', 'Muhammad Khoirun Nizam', '#DigitalisasiZISWAF #TemanAmal #LAZISMUTulungagung #ZakatDigital #FilantropiModern #MuhammadiyahBerdaya', '2025-10-21 03:11:48', '2026-06-22 02:53:14', 'published', 111),
(21, 'berita', 'Dari HPT Jilid 3 hingga Homo Sapiens: IMM Tulungagung Bedah Nalar Politik di Seminar Kebangsaan', 'dari-hpt-jilid-3-hingga-homo-sapiens-imm-tulungagung-bedah-nalar-politik-di-seminar-kebangsaan', 'Suasana Lotu’s Garden, Senin malam (17/11), berubah menjadi forum intelektual yang hangat ketika Pimpinan Cabang Ikatan Mahasiswa Muhammadiyah (PC IMM) Tulungagung menggelar Seminar Kebangsaan. Acara ini mempertemukan dua narasumber dengan perspektif tajam dan saling melengkapi: Imam Khoirudin (Fokal IMM) dan Rijal Abdullah (Anggota DPRD Tulungagung).', 'temanamal.org – Suasana Lotu’s Garden, Senin malam (17/11), berubah menjadi forum intelektual yang hangat ketika Pimpinan Cabang Ikatan Mahasiswa Muhammadiyah (PC IMM) Tulungagung menggelar Seminar Kebangsaan. Acara ini mempertemukan dua narasumber dengan perspektif tajam dan saling melengkapi: Imam Khoirudin (Fokal IMM) dan Rijal Abdullah (Anggota DPRD Tulungagung).\r\nKeduanya mengajak peserta menyelami nalar politik dari dua sudut pandang berbeda—etika kepemimpinan Muhammadiyah dan dinamika sejarah peradaban manusia.\r\nImam Khoirudin: Politik adalah Realitas Sehari-hari\r\nDalam pemaparannya, Imam Khoirudin menegaskan bahwa politik bukan sesuatu yang tabu, melainkan bagian dari kehidupan manusia sejak membuka mata.\r\n“Berbicara politik adalah hal yang lumrah. Setiap hari kita bersentuhan dengan politik, apalagi di era digital seperti sekarang,” ujarnya.\r\nImam kemudian menguraikan lima kriteria kepemimpinan menurut Himpunan Putusan Tarjih (HPT) Jilid 3 sebagai pedoman bagi kader IMM dalam memilih pemimpin yang layak:\r\nIntegritas – Kejujuran moral yang tidak bisa ditawar.\r\nKapasitas – Kemampuan intelektual dan kecakapan manajerial.\r\nPopulis – Keberpihakan nyata kepada rakyat banyak.\r\nVisioner – Mampu melihat dan merencanakan masa depan.\r\nKenegarawanan – Menempatkan kepentingan bangsa di atas kepentingan golongan.\r\nBagi Imam, kelima indikator ini adalah standar minimal yang wajib dipegang jika IMM ingin berperan sebagai kekuatan moral-politik.\r\nRijal Abdullah: Politik “Abu-Abu” dan Kekuatan Narasi\r\nBerbeda dengan Imam, Rijal Abdullah membawa peserta berjalan jauh menelusuri sejarah peradaban manusia. Mengutip gagasan dari Homo Sapiens, ia memaparkan bahwa peradaban manusia berkembang melalui kemampuan bercerita dan membangun narasi.\r\nMenurutnya, politik dan ekonomi selalu berada di wilayah “abu-abu”, penuh ketidakpastian dan rentan manipulasi wacana.\r\n“Manusia adalah satu-satunya makhluk yang bisa membuat cerita, termasuk narasi yang mengada-ada, hanya demi melegitimasi kekuasaan,” tegas Rijal.\r\nIa juga menyinggung dinamika wacana yang pernah muncul di Indonesia, mulai dari isu “Islam Nusantara” pada 2016 hingga narasi “Radikalisme”, yang menurutnya tidak lepas dari kepentingan politik tertentu.\r\nRijal turut menyentuh konsep revolusi kognitif manusia—dari ditemukannya api, berkembangnya pertanian, hingga memasuki Revolusi Kognitif ke-6: Artificial Intelligence (AI).\r\nDiskusi semakin menghangat ketika Rijal mengaitkan literatur besar seperti Asas Anna Karenina dalam konteks kebahagiaan serta pemikiran Tan Malaka tentang kaum borjuis sebagai struktur penindasan kelas.\r\nDialektika Pemikiran: Moralitas dan Realisme Sejarah\r\nPertemuan dua gagasan—idealisme kepemimpinan berdasarkan HPT Jilid 3 dari Imam Khoirudin dan realisme historis dari Rijal Abdullah—menciptakan diskusi dialektis yang mendalam. Peserta tidak hanya diajak menilai karakter calon pemimpin, tetapi juga memahami bagaimana narasi politik dibangun dan bagaimana peradaban manusia membentuk pola kekuasaan.\r\nSeminar ini membuktikan bahwa mahasiswa IMM Tulungagung masih memiliki daya kritis dan taring intelektual untuk menganalisis arah politik daerah maupun nasional.\r\nMalam itu, Lotu’s Garden bukan sekadar venue diskusi—tetapi menjadi ruang lahirnya kesadaran politik baru bagi para kader muda Muhammadiyah.', '1763429992_691bce680574c.jpg', 'Acara Berlangsung', 'Muhammad Khoirun Nizam', 'education, PC IMM Tulungagung, DPRD Tulungagung', '2025-11-18 01:39:52', '2026-06-22 02:53:26', 'published', 119),
(22, 'berita', 'Rijal Abdullah Panaskan Forum Seminar Kebangsaan IMM Tulungagung: Bongkar Politik Abu-Abu, Narasi Kekuasaan, hingga Revolusi Kognitif ke-6', 'rijal-abdullah-panaskan-forum-seminar-kebangsaan-imm-tulungagung-bongkar-politik-abu-abu-narasi-kekuasaan-hingga-revolusi-kognitif-ke-6', 'Seminar Kebangsaan yang diselenggarakan Pimpinan Cabang Ikatan Mahasiswa Muhammadiyah (PC IMM) Tulungagung di Lotus Garden Tulungagung, Senin (17/11/2025) berlangsung dinamis dan penuh gagasan kritis. Hal itu terjadi setelah pemantik kedua, Semala Rijal Abdullah, S.IP., M.Ap, menyampaikan materi tentang politik, narasi kekuasaan, dan perkembangan peradaban manusia di era Artificial Intelligence (AI).', 'temanamal.org  – Seminar Kebangsaan yang diselenggarakan Pimpinan Cabang Ikatan Mahasiswa Muhammadiyah (PC IMM) Tulungagung di Lotus Garden Tulungagung, Senin (17/11/2025) berlangsung dinamis dan penuh gagasan kritis. Hal itu terjadi setelah pemantik kedua, Semala Rijal Abdullah, S.IP., M.Ap, menyampaikan materi tentang politik, narasi kekuasaan, dan perkembangan peradaban manusia di era Artificial Intelligence (AI).\r\n\r\nPolitik sebagai Ruang Abu-Abu\r\n\r\nDalam pemaparannya, Rijal menyampaikan bahwa dunia politik tidak pernah berdiri pada posisi hitam-putih. Ia menyebut politik dan ekonomi selalu berada pada wilayah “abu-abu” yang sangat rentan terhadap bias, interpretasi kepentingan, dan manipulasi narasi.\r\n\r\n“Manusia adalah satu-satunya makhluk yang mampu membangun cerita. Termasuk narasi yang sengaja dibentuk untuk melegitimasi kekuasaan,” ujarnya.\r\n\r\nMenurut Rijal, kemampuan manusia menciptakan cerita inilah yang membuat narasi menjadi salah satu instrumen paling efektif dalam relasi kuasa.\r\n\r\nMenyinggung Narasi di Indonesia\r\nRijal juga menyoroti beberapa narasi besar yang pernah berkembang di Indonesia satu dekade terakhir. Di antaranya wacana Islam Nusantara pada 2016 serta isu Radikalisme yang menguat setelahnya.\r\n\r\nIa menegaskan bahwa dua isu tersebut tidak dapat dilepaskan dari dinamika politik nasional.\r\n“Setiap narasi besar yang muncul di publik pasti memiliki kepentingan. Masyarakat perlu lebih peka dalam membaca arah dari sebuah wacana,” jelasnya.\r\n\r\nPemaparan ini disambut serius oleh peserta, terlihat dari antusiasme pada sesi diskusi dan tanggapan yang muncul setelah pemaparan.\r\n\r\nRevolusi Kognitif ke-6 dan Dampaknya bagi Peradaban\r\nDi bagian akhir, Rijal menjelaskan perjalanan revolusi kognitif manusia—mulai dari penemuan api, perkembangan pertanian, hingga era teknologi modern. Ia menyampaikan bahwa manusia saat ini memasuki fase baru yang ia sebut sebagai Revolusi Kognitif ke-6, ditandai dengan perkembangan kecerdasan buatan.\r\n\r\n“AI kini dapat membangun narasi, memproduksi informasi, bahkan menciptakan realitas alternatif. Ini tantangan besar bagi masyarakat, termasuk kader IMM,” ungkapnya.\r\nRijal menekankan pentingnya literasi digital dan kemampuan berpikir kritis untuk menghadapi perubahan besar yang dipicu oleh teknologi kecerdasan buatan.\r\n\r\nForum Berjalan Dinamis\r\nSeminar yang dihadiri kader IMM dari berbagai komisariat ini berlangsung hidup dan produktif. Peserta terlihat aktif memberikan pertanyaan dan tanggapan selama sesi diskusi.\r\n\r\nRijal berharap kader IMM Tulungagung mampu menjadi kelompok cendekia yang tidak hanya memahami politik sebagai perebutan kekuasaan, tetapi juga sebagai arena kontestasi narasi.\r\n\r\n“Ke depan, siapa yang menguasai narasi, dialah yang menguasai arah peradaban,” pungkasnya.', '1763435816_691be528e15da.jpg', 'foto Bapak Rijal Abdulloh', 'Muhammad Khoirun Nizam', '#sosial, #lazismu Tulungagung, #LAZISMU AG raya, #temanamal', '2025-11-18 03:16:57', '2026-06-22 02:53:15', 'published', 115);
